//загружаем инфоканал по идентификатору
var infoChannel = PublicAPI.Portal.Objects.Messages.InformationChannel.Load(3);
//загружаем пользователя по идентифифкатору
var messAuthor = PublicAPI.Portal.Security.User.Load(3); 
//тема сообщения
var messSubject = "тема для сообщения";
//текст сообщения
var messText = "текст сообщения";

//отправляем сообщение в инфоканал
PublicAPI.Portal.Messages.AddMessageToInfoChannel(messSubject, messText, infoChannel, messAuthor);

